package com.taxin60sec.backend.controller;
import com.taxin60sec.backend.common.ApiResponse; import com.taxin60sec.backend.dto.business.*; import com.taxin60sec.backend.service.BusinessProfileService; import io.swagger.v3.oas.annotations.Operation; import io.swagger.v3.oas.annotations.tags.Tag; import jakarta.servlet.http.HttpServletRequest; import jakarta.validation.Valid; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/v1/businesses") @Tag(name="Business Profiles",description="Client business management")
public class BusinessProfileController { private final BusinessProfileService service; public BusinessProfileController(BusinessProfileService service){this.service=service;} @PostMapping @PreAuthorize("hasAnyRole('CLIENT','ADMIN')") @Operation(summary="Create a business") public ApiResponse<BusinessProfileResponse> create(@Valid @RequestBody BusinessProfileRequest body,HttpServletRequest request){return ApiResponse.success("Business created",service.createBusiness(body),request.getRequestURI());} @GetMapping("/{id}") @Operation(summary="Get a business") public ApiResponse<BusinessProfileResponse> get(@PathVariable Long id,HttpServletRequest request){return ApiResponse.success("Business retrieved",service.getBusiness(id),request.getRequestURI());} @GetMapping("/client/{clientId}") @Operation(summary="List a client's businesses") public ApiResponse<List<BusinessProfileResponse>> list(@PathVariable Long clientId,HttpServletRequest request){return ApiResponse.success("Businesses retrieved",service.getBusinessesForClient(clientId),request.getRequestURI());} @PutMapping("/{id}") @PreAuthorize("hasAnyRole('CLIENT','ADMIN')") @Operation(summary="Update a business") public ApiResponse<BusinessProfileResponse> update(@PathVariable Long id,@Valid @RequestBody BusinessProfileRequest body,HttpServletRequest request){return ApiResponse.success("Business updated",service.updateBusiness(id,body),request.getRequestURI());} @DeleteMapping("/{id}") @PreAuthorize("hasAnyRole('CLIENT','ADMIN')") @Operation(summary="Delete a business") public ApiResponse<Void> delete(@PathVariable Long id,HttpServletRequest request){service.deleteBusiness(id);return ApiResponse.success("Business deleted",null,request.getRequestURI());} }
